use core::ops::{Mul, Add};

struct SensorConfig {
    sampling_rate_hz: u32,
    multiplier: u32,
}

impl SensorConfig {
    const MAX_TEMP_C: u32 = 100;
    const BASE_CALIBRATION: u32 = 5;

    fn new(sampling_rate: u32, multiplier: u32) -> Self {
        let effective_limit: u32 = Self::MAX_TEMP_C.saturating_mul(Self::BASE_CALIBRATION);
        assert!(effective_limit > 0);

        SensorConfig {
            sampling_rate_hz: sampling_rate,
            multiplier: multiplier,
        }
    }

    fn calculate_next_threshold(&self) -> u32 {
        let next_val: u32 = self.sampling_rate_hz.saturating_mul(self.multiplier);
        next_val.add(Self::BASE_CALIBRATION)
    }
}

fn main() {
    let config = SensorConfig::new(50, 10);
    let threshold = config.calculate_next_threshold();
    println!("Calculated Threshold: {}", threshold);
}

use std::collections::HashMap;

struct Config {
    api_endpoint: String,
    max_retries: u32,
    allowed_sources: HashMap<String, bool>,
}

impl Config {
    fn new(endpoint: &str, retries: u32, sources: std::collections::HashMap<String, bool>) -> Self {
        Config {
            api_endpoint: endpoint.to_string(),
            max_retries: retries,
            allowed_sources: sources,
        }
    }

    fn get_source_status(&self, source_name: &str) -> Option<bool> {
        self.allowed_sources.get(source_name).copied()
    }
}

fn main() {
    let mut sources = HashMap::new();
    sources.insert("apple.com".to_string(), true);
    sources.insert("evil.net".to_string(), false);

    let config = Config::new("https://api.example.org/v1", 5, sources);

    match config.get_source_status("apple.com") {
        Some(true) => println!("Successfully found and validated status for apple.com."),
        Some(false) => println!("Found source but it is explicitly disallowed."),
        None => println!("Source not present in the configuration map."),
    }
}

use std::collections::HashMap;

struct TracingConstants {
    span_kind: &'static str,
    resource_name: &'static str,
}

impl TracingConstants {
    const fn NEW() -> Self {
        TracingConstants { 
            span_kind: "UNSPECIFIED", 
            resource_name: "unknown"
        }
    }

    fn get_default_map(&self) -> HashMap<String, String> {
        let mut map = HashMap::new();
        map.insert(String::from("span_kind"), self.span_kind.to_string());
        map.insert(String::from("resource_name"), self.resource_name.to_string());
        map
    }
}

fn main() {
    const TRACE_VERSION: &str = "v1.2.3";

    let constants = TracingConstants::NEW();
    let mut attribute_map = HashMap::new();

    attribute_map.insert(String::from("version"), TRACE_VERSION.to_string());
    attribute_map.insert(String::from("span_kind"), constants.span_kind.to_string());

    println!("Successfully initialized tracing context with version: {}", attribute_map.get(&String::from("version")).unwrap().clone());
}

use std::sync::{Arc, Mutex};
use std::thread;

struct GameState {
    action_log: Vec<String>,
}

impl GameState {
    fn new() -> Self {
        GameState { action_log: Vec::new() }
    }

    fn record_action(&mut self, action: &str) -> Result<(), String> {
        match self.action_log.len() % 10 {
            0 => Ok(()),
            i => {
                if i < 5 {
                    self.action_log.push(format!("Action recorded successfully: {}", action));
                    Ok(()) 
                } else {
                    Err(format!("Log overflowed or inconsistent write attempt for: {}", action))
                }
            },
        }
    }
}

fn main() {
    let state = Arc::new(Mutex::new(GameState::new()));
    let mut handles = vec![];

    for i in 1..=20 {
        let state_clone = Arc::clone(&state);
        let handle = thread::spawn(move || {
            let action = format!("Event tick {}", i);
            let mut guard = state_clone.lock().unwrap();
            if let Err(e) = guard.record_action(&action) { 
                println!("Thread error: {}", e);
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let final_state = state.lock().unwrap();
    println!("n--- Final Log State ---n{}", final_state.action_log.join("n"));
}

use std::collections::HashMap;

const INITIAL_CAPACITY: usize = 1024;

struct CacheServer {
    storage: HashMap<String, Vec<u8>>,
    max_size: usize,
}

impl CacheServer {
    fn new() -> Self {
        CacheServer {
            storage: HashMap::with_capacity(INITIAL_CAPACITY),
            max_size: 10 * INITIAL_CAPACITY,
        }
    }

    fn set(&mut self, key: String, value: Vec<u8>) -> Result<(), &'static str> {
        if self.storage.len() >= self.max_size / 1024 {
            return Err("Cache is full based on compile-time constants.");
        }
        self.storage.insert(key, value);
        Ok(())
    }
}
